Index: web/server/api/dio/webhook.ts
===================================================================
--- web/server/api/dio/webhook.ts	
+++ web/server/api/dio/webhook.ts	
@@ -0,0 +1,102 @@
+import { createError, defineEventHandler, getHeader, readRawBody } from "h3";
+import { useStorage } from "nitro/storage";
+import {
+	createBifrostVirtualKey,
+	getDioEnvConfig,
+	loadDioEntitlement,
+	markEventProcessed,
+	parseCreemWebhookBody,
+	saveDioEntitlement,
+	verifyCreemWebhookSignature,
+	type DioEntitlement,
+} from "../../../src/dio-provider/server";
+
+export default defineEventHandler(async (event) => {
+	if (event.method !== "POST") {
+		throw createError({ statusCode: 405, statusMessage: "Method not allowed" });
+	}
+
+	const config = getDioEnvConfig();
+	const bodyString = (await readRawBody(event)) ?? "";
+	const signature = getHeader(event, "creem-signature") ?? "";
+
+	if (!verifyCreemWebhookSignature(bodyString, signature, config.creemWebhookSecret)) {
+		throw createError({ statusCode: 401, statusMessage: "Invalid webhook signature" });
+	}
+
+	let payload: ReturnType<typeof parseCreemWebhookBody>;
+	try {
+		payload = parseCreemWebhookBody(JSON.parse(bodyString));
+	} catch (err) {
+		throw createError({
+			statusCode: 400,
+			statusMessage: err instanceof Error ? err.message : "Invalid webhook payload",
+		});
+	}
+
+	if (payload.eventType !== "checkout.completed") {
+		return { received: true, handled: false };
+	}
+
+	const storage = useStorage("keating:dio");
+	const wasNew = await markEventProcessed(storage, payload.id);
+	if (!wasNew) {
+		return { received: true, handled: false, reason: "duplicate event" };
+	}
+
+	const object = payload.object;
+	const productId = object?.order?.product || object?.product?.id;
+	if (productId !== config.creemProductId) {
+		throw createError({ statusCode: 400, statusMessage: "Product ID mismatch" });
+	}
+
+	const customerEmail = object?.customer?.email;
+	if (!customerEmail) {
+		throw createError({ statusCode: 400, statusMessage: "Missing customer email" });
+	}
+	const email = customerEmail.toLowerCase();
+
+	const existing = await loadDioEntitlement(storage, email);
+	if (existing) {
+		return { received: true, handled: true, entitlement: { email, virtualKeyId: existing.virtualKeyId } };
+	}
+
+	const purchaseReference =
+		(object?.request_id as string | undefined) ||
+		(typeof object?.metadata?.dio_purchase_reference === "string"
+			? object.metadata.dio_purchase_reference
+			: undefined) ||
+		payload.id;
+
+	const virtualKey = await createBifrostVirtualKey(config, {
+		name: `keating:${email}:${purchaseReference}`,
+		description: `Keating Dio credits for ${email}. Creem checkout ${object?.id ?? "unknown"}, order ${object?.order?.id ?? "unknown"}`,
+		allowedModels: [config.bifrostModelAlias],
+		budget: { max: config.dioCreditBudget },
+		metadata: {
+			email,
+			purchaseReference,
+			creemEventId: payload.id,
+			creemCheckoutId: object?.id,
+			creemOrderId: object?.order?.id,
+			creemProductId: productId,
+			creemCustomerId: object?.customer?.id,
+			source: "creem-webhook",
+		},
+	});
+
+	const entitlement: DioEntitlement = {
+		email,
+		virtualKeyId: virtualKey.id,
+		virtualKeyValue: virtualKey.value,
+		purchaseReference,
+		orderId: object?.order?.id,
+		checkoutId: object?.id,
+		productId,
+		customerId: object?.customer?.id,
+		createdAt: new Date().toISOString(),
+	};
+	await saveDioEntitlement(storage, entitlement);
+
+	return { received: true, handled: true, entitlement: { email, virtualKeyId: virtualKey.id } };
+});

Index: web/src/components/DioAccessPromptDialog.tsx
===================================================================
--- web/src/components/DioAccessPromptDialog.tsx	
+++ web/src/components/DioAccessPromptDialog.tsx	
@@ -0,0 +1,330 @@
+import { useEffect, useState } from "react";
+import { getAppStorage } from "@earendil-works/pi-web-ui";
+import { KeyRound, X } from "lucide-react";
+import {
+	DIO_PROVIDER_ID,
+	claimDioAccess,
+	recoverDioAccess,
+	startDioCheckout,
+	normalizeEmail,
+} from "../dio-provider";
+
+type DioPromptRequest = {
+	id: string;
+	resolve: (success: boolean) => void;
+};
+
+let activeDioPrompt: DioPromptRequest | null = null;
+
+export function getActiveDioPrompt(): DioPromptRequest | null {
+	return activeDioPrompt;
+}
+
+function emitDioPromptChange() {
+	window.dispatchEvent(new CustomEvent("keating:dio-prompt-changed"));
+}
+
+export async function promptDioAccess(): Promise<boolean> {
+	if (typeof window === "undefined") return false;
+	const existing = await getAppStorage().providerKeys.get(DIO_PROVIDER_ID);
+	if (existing) return true;
+
+	if (activeDioPrompt) {
+		activeDioPrompt.resolve(false);
+	}
+
+	return new Promise((resolve) => {
+		activeDioPrompt = {
+			id: crypto.randomUUID(),
+			resolve,
+		};
+		emitDioPromptChange();
+	});
+}
+
+export function closeDioPrompt(success: boolean) {
+	if (!activeDioPrompt) return;
+	const request = activeDioPrompt;
+	activeDioPrompt = null;
+	request.resolve(success);
+	emitDioPromptChange();
+}
+
+export function DioAccessPromptDialog() {
+	const [request, setRequest] = useState(activeDioPrompt);
+	const [email, setEmail] = useState("");
+	const [mode, setMode] = useState<"purchase" | "recover" | "manual">("purchase");
+	const [apiKey, setApiKey] = useState("");
+	const [purchaseReference, setPurchaseReference] = useState("");
+	const [loading, setLoading] = useState(false);
+	const [error, setError] = useState("");
+
+	useEffect(() => {
+		const sync = () => {
+			setRequest(activeDioPrompt);
+			setEmail("");
+			setMode("purchase");
+			setApiKey("");
+			setPurchaseReference("");
+			setError("");
+			setLoading(false);
+		};
+		window.addEventListener("keating:dio-prompt-changed", sync);
+		return () => window.removeEventListener("keating:dio-prompt-changed", sync);
+	}, []);
+
+	if (!request) return null;
+
+	const saveManualKey = async () => {
+		const trimmed = apiKey.trim();
+		if (!trimmed) {
+			setError("Enter an API key first.");
+			return;
+		}
+		setLoading(true);
+		setError("");
+		try {
+			await getAppStorage().providerKeys.set(DIO_PROVIDER_ID, trimmed);
+			closeDioPrompt(true);
+		} catch (err) {
+			setError(err instanceof Error ? err.message : String(err));
+		} finally {
+			setLoading(false);
+		}
+	};
+
+	const doCheckout = async () => {
+		const normalized = normalizeEmail(email);
+		if (!isValidEmail(normalized)) {
+			setError("Enter a valid email address.");
+			return;
+		}
+		setLoading(true);
+		setError("");
+		try {
+			const result = await startDioCheckout(normalized);
+			setPurchaseReference(result.purchaseReference);
+			window.open(result.checkoutUrl, "_blank", "noopener,noreferrer");
+		} catch (err) {
+			setError(err instanceof Error ? err.message : String(err));
+		} finally {
+			setLoading(false);
+		}
+	};
+
+	const doClaim = async () => {
+		const normalized = normalizeEmail(email);
+		if (!isValidEmail(normalized)) {
+			setError("Enter a valid email address.");
+			return;
+		}
+		setLoading(true);
+		setError("");
+		try {
+			const result = await claimDioAccess(normalized, purchaseReference || undefined);
+			if (result.success && result.apiKey) {
+				await getAppStorage().providerKeys.set(DIO_PROVIDER_ID, result.apiKey);
+				closeDioPrompt(true);
+			} else if (result.pending) {
+				setError("Purchase is still pending. Complete payment and try again.");
+			} else {
+				setError("Could not find a completed purchase for this email.");
+			}
+		} catch (err) {
+			setError(err instanceof Error ? err.message : String(err));
+		} finally {
+			setLoading(false);
+		}
+	};
+
+	const doRecover = async () => {
+		const normalized = normalizeEmail(email);
+		if (!isValidEmail(normalized)) {
+			setError("Enter a valid email address.");
+			return;
+		}
+		setLoading(true);
+		setError("");
+		try {
+			const result = await recoverDioAccess(normalized);
+			if (result.success && result.apiKey) {
+				await getAppStorage().providerKeys.set(DIO_PROVIDER_ID, result.apiKey);
+				closeDioPrompt(true);
+			} else {
+				setError("No active access found for this email.");
+			}
+		} catch (err) {
+			setError(err instanceof Error ? err.message : String(err));
+		} finally {
+			setLoading(false);
+		}
+	};
+
+	return (
+		<div className="fixed inset-0 z-[100] flex items-center justify-center bg-background/70 p-4 backdrop-blur-sm">
+			<div className="w-full max-w-md rounded-lg border border-border bg-background shadow-xl">
+				<div className="flex items-center justify-between gap-3 border-b border-border px-4 py-3">
+					<div className="flex items-center gap-2">
+						<KeyRound size={16} className="text-primary" />
+						<h2 className="text-sm font-semibold">Dio access</h2>
+					</div>
+					<button
+						type="button"
+						className="inline-flex h-8 w-8 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-foreground"
+						onClick={() => closeDioPrompt(false)}
+						aria-label="Close"
+					>
+						<X size={16} />
+					</button>
+				</div>
+				<div className="space-y-3 p-4">
+					{mode === "purchase" && (
+						<>
+							<p className="text-sm text-muted-foreground">
+								Kimi K2.6 runs through Dio. Buy credits to get a Bifrost API key automatically.
+							</p>
+							<input
+								type="email"
+								className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
+								placeholder="Your email address"
+								value={email}
+								onChange={(event) => setEmail(event.target.value)}
+								onKeyDown={(event) => {
+									if (event.key === "Enter") void doCheckout();
+									if (event.key === "Escape") closeDioPrompt(false);
+								}}
+								autoFocus
+							/>
+							{purchaseReference && (
+								<p className="text-xs text-muted-foreground">
+									After completing checkout, click Claim to retrieve your key.
+								</p>
+							)}
+							<div className="flex flex-wrap items-center justify-between gap-3">
+								<button
+									type="button"
+									className="text-xs text-primary underline underline-offset-2"
+									onClick={() => setMode("recover")}
+								>
+									Recover access by email
+								</button>
+								<div className="flex gap-2">
+									{purchaseReference && (
+										<button
+											type="button"
+											className="inline-flex h-9 items-center rounded-md bg-secondary px-3 text-sm font-medium hover:bg-secondary/80 disabled:opacity-50"
+											onClick={doClaim}
+											disabled={loading}
+										>
+											{loading ? "Claiming..." : "Claim"}
+										</button>
+									)}
+									<button
+										type="button"
+										className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
+										onClick={doCheckout}
+										disabled={loading}
+									>
+										{loading
+											? "Loading..."
+											: purchaseReference
+												? "Open checkout again"
+												: "Buy credits"}
+									</button>
+								</div>
+							</div>
+						</>
+					)}
+					{mode === "recover" && (
+						<>
+							<p className="text-sm text-muted-foreground">
+								Enter the email you used to buy Dio credits. We'll restore your Bifrost key.
+							</p>
+							<input
+								type="email"
+								className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
+								placeholder="Your email address"
+								value={email}
+								onChange={(event) => setEmail(event.target.value)}
+								onKeyDown={(event) => {
+									if (event.key === "Enter") void doRecover();
+									if (event.key === "Escape") closeDioPrompt(false);
+								}}
+								autoFocus
+							/>
+							<div className="flex flex-wrap items-center justify-between gap-3">
+								<button
+									type="button"
+									className="text-xs text-primary underline underline-offset-2"
+									onClick={() => setMode("purchase")}
+								>
+									Buy credits
+								</button>
+								<button
+									type="button"
+									className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
+									onClick={doRecover}
+									disabled={loading}
+								>
+									{loading ? "Recovering..." : "Recover access"}
+								</button>
+							</div>
+						</>
+					)}
+					{mode === "manual" && (
+						<>
+							<p className="text-sm text-muted-foreground">
+								Paste a Bifrost virtual key manually. For development and support only.
+							</p>
+							<input
+								type="password"
+								className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
+								placeholder="Dio virtual key"
+								value={apiKey}
+								onChange={(event) => setApiKey(event.target.value)}
+								onKeyDown={(event) => {
+									if (event.key === "Enter") void saveManualKey();
+									if (event.key === "Escape") closeDioPrompt(false);
+								}}
+								autoFocus
+							/>
+							<div className="flex flex-wrap items-center justify-between gap-3">
+								<button
+									type="button"
+									className="text-xs text-primary underline underline-offset-2"
+									onClick={() => setMode("purchase")}
+								>
+									Back to purchase
+								</button>
+								<button
+									type="button"
+									className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
+									onClick={saveManualKey}
+									disabled={loading}
+								>
+									{loading ? "Saving..." : "Save key"}
+								</button>
+							</div>
+						</>
+					)}
+					<div className="flex items-center justify-between">
+						{mode !== "manual" && (
+							<button
+								type="button"
+								className="text-xs text-muted-foreground underline underline-offset-2"
+								onClick={() => setMode("manual")}
+							>
+								Advanced: paste key manually
+							</button>
+						)}
+					</div>
+					{error && <div className="text-xs text-destructive">{error}</div>}
+				</div>
+			</div>
+		</div>
+	);
+}
+
+function isValidEmail(email: string): boolean {
+	return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
+}

