import type { Api, Model } from "@earendil-works/pi-ai";

export const DIO_PROVIDER_ID = "dio";
export const DIO_BASE_URL = "https://bifrost.dio.computer/v1";
export const DIO_GATEWAY_BASE_URL = "https://bifrost.dio.computer";
export const DIO_DEFAULT_MODEL_ID = "kimi-k2.6";
export const DIO_MODEL_ALIAS_OVERRIDE = "kimi-k2.6";

export interface DioProviderDefinition {
	id: string;
	label: string;
	baseUrl: string;
	api: "openai-completions";
}

export const dioProviderDefinition: DioProviderDefinition = {
	id: DIO_PROVIDER_ID,
	label: "Dio",
	baseUrl: DIO_BASE_URL,
	api: "openai-completions",
};

export const DIO_DEFAULT_MODEL: Model<"openai-completions"> = {
	id: DIO_MODEL_ALIAS_OVERRIDE,
	name: "Kimi K2.6",
	api: "openai-completions",
	provider: DIO_PROVIDER_ID,
	baseUrl: DIO_BASE_URL,
	reasoning: true,
	input: ["text"],
	cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0 },
	contextWindow: 256_000,
	maxTokens: 8192,
};

export interface DioAccessStatus {
	hasKey: boolean;
}

export interface DioCheckoutResult {
	checkoutUrl: string;
	purchaseReference: string;
}

export interface DioClaimResult {
	success: boolean;
	apiKey?: string;
	pending?: boolean;
}

export async function getDioAccessStatus(): Promise<DioAccessStatus> {
	const { getAppStorage } = await import("@earendil-works/pi-web-ui");
	const key = await getAppStorage().providerKeys.get(DIO_PROVIDER_ID);
	return { hasKey: typeof key === "string" && key.length > 0 };
}

export async function startDioCheckout(email: string): Promise<DioCheckoutResult> {
	const response = await fetch("/api/dio/checkout", {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({ email: normalizeEmail(email) }),
	});
	const body = await response.json().catch(() => ({}));
	if (!response.ok) {
		throw new Error(typeof body.error === "string" ? body.error : `Checkout failed (${response.status})`);
	}
	return body as DioCheckoutResult;
}

export async function claimDioAccess(email: string, purchaseReference?: string): Promise<DioClaimResult> {
	const response = await fetch("/api/dio/claim", {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({ email: normalizeEmail(email), purchaseReference }),
	});
	const body = await response.json().catch(() => ({}));
	if (!response.ok) {
		throw new Error(typeof body.error === "string" ? body.error : `Claim failed (${response.status})`);
	}
	return body as DioClaimResult;
}

export async function recoverDioAccess(email: string): Promise<DioClaimResult> {
	const response = await fetch("/api/dio/recover", {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({ email: normalizeEmail(email) }),
	});
	const body = await response.json().catch(() => ({}));
	if (!response.ok) {
		throw new Error(typeof body.error === "string" ? body.error : `Recovery failed (${response.status})`);
	}
	return body as DioClaimResult;
}

export function normalizeEmail(email: string): string {
	return email.trim().toLowerCase();
}

export function isDioProvider(provider: string): boolean {
	return provider === DIO_PROVIDER_ID;
}

import { createHmac, timingSafeEqual } from "node:crypto";
import { normalizeEmail } from "./index";

export interface DioEnvConfig {
	creemApiKey: string;
	creemWebhookSecret: string;
	creemProductId: string;
	creemBaseUrl: string;
	 dioCreditBudget: number;
	bifrostApiKey: string;
	bifrostBaseUrl: string;
	bifrostModelAlias: string;
}

export function getDioEnvConfig(): DioEnvConfig {
	const creemApiKey = getRequiredEnv("CREEM_API_KEY");
	const creemWebhookSecret = getRequiredEnv("CREEM_WEBHOOK_SECRET");
	const creemProductId = getRequiredEnv("CREEM_PRODUCT_ID_DIO_CREDITS");
	const dioCreditBudget = Number.parseInt(getRequiredEnv("DIO_CREDIT_BUDGET"), 10);
	const bifrostApiKey = getRequiredEnv("BIFROST_API_KEY");

	if (!Number.isFinite(dioCreditBudget) || dioCreditBudget <= 0) {
		throw new Error("DIO_CREDIT_BUDGET must be a positive integer");
	}

	return {
		creemApiKey,
		creemWebhookSecret,
		creemProductId,
		creemBaseUrl: process.env.CREEM_BASE_URL || "https://api.creem.io/v1",
		dioCreditBudget,
		bifrostApiKey,
		bifrostBaseUrl: process.env.BIFROST_BASE_URL || "https://bifrost.dio.computer",
		bifrostModelAlias: process.env.BIFROST_MODEL_ALIAS || "kimi-k2.6",
	};
}

function getRequiredEnv(name: string): string {
	const value = process.env[name]?.trim();
	if (!value) {
		throw new Error(`Missing required environment variable: ${name}`);
	}
	return value;
}

export interface CreemCheckoutPayload {
	email: string;
}

export interface CreemCheckoutResponse {
	checkoutUrl: string;
	purchaseReference: string;
}

export async function createCreemCheckout(
	config: DioEnvConfig,
	email: string,
): Promise<CreemCheckoutResponse> {
	const normalized = normalizeEmail(email);
	if (!isValidEmail(normalized)) {
		throw new Error("Invalid email address");
	}

	const purchaseReference = `dio_${cryptoUUID()}`;

	const response = await fetch(`${config.creemBaseUrl.replace(/\/+$/, "")}/checkouts`, {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			"x-api-key": config.creemApiKey,
		},
		body: JSON.stringify({
			product_id: config.creemProductId,
			success_url: `${process.env.KEATING_WEB_ORIGIN || ""}/dio/success`,
			request_id: purchaseReference,
			metadata: {
				dio_purchase_reference: purchaseReference,
				customer_email: normalized,
			},
		}),
	});

	const body = await response.json().catch(() => ({}));
	if (!response.ok) {
		const message = body?.message || body?.error || `Creem checkout failed (${response.status})`;
		throw new Error(message);
	}

	const checkoutUrl = body?.checkout_url || body?.checkoutUrl;
	if (typeof checkoutUrl !== "string") {
		throw new Error("Creem checkout response missing checkout URL");
	}

	return {
		checkoutUrl,
		purchaseReference,
	};
}

export interface CreemWebhookEvent {
	id: string;
	eventType: string;
	created_at?: number;
	object?: {
		id?: string;
		object?: string;
		request_id?: string;
		order?: { id?: string; product?: string; status?: string };
		product?: { id?: string };
		customer?: { id?: string; email?: string };
		metadata?: Record<string, unknown>;
	};
}

export function parseCreemWebhookBody(body: unknown): CreemWebhookEvent {
	if (!body || typeof body !== "object") {
		throw new Error("Invalid webhook payload");
	}
	const payload = body as Record<string, unknown>;
	if (typeof payload.id !== "string" || !payload.id) {
		throw new Error("Invalid webhook event id");
	}
	if (typeof payload.eventType !== "string" || !payload.eventType) {
		throw new Error("Invalid webhook event type");
	}
	if (!payload.object || typeof payload.object !== "object") {
		throw new Error("Invalid webhook object");
	}
	return payload as CreemWebhookEvent;
}

export function verifyCreemWebhookSignature(body: string, signature: string, secret: string): boolean {
	if (!signature) return false;
	const computed = createHmac("sha256", secret).update(body).digest("hex");
	if (computed.length !== signature.length) return false;
	try {
		const computedBuf = Buffer.from(computed, "hex");
		const signatureBuf = Buffer.from(signature, "hex");
		return timingSafeEqual(computedBuf, signatureBuf);
	} catch {
		return false;
	}
}

export interface BifrostVirtualKeyRequest {
	name: string;
	description: string;
	allowedModels: string[];
	budget: { max: number };
	metadata: Record<string, unknown>;
}

export interface BifrostVirtualKey {
	id: string;
	value: string;
}

export async function createBifrostVirtualKey(
	config: DioEnvConfig,
	request: BifrostVirtualKeyRequest,
): Promise<BifrostVirtualKey> {
	const url = `${config.bifrostBaseUrl.replace(/\/+$/, "")}/api/governance/virtual-keys`;
	const response = await fetch(url, {
		method: "POST",
		headers: {
			"Content-Type": "application/json",
			Authorization: `Bearer ${config.bifrostApiKey}`,
		},
		body: JSON.stringify({
			name: request.name,
			description: request.description,
			allowed_models: request.allowedModels,
			budget: request.budget,
			metadata: request.metadata,
		}),
	});

	const body = await response.json().catch(() => ({}));
	if (!response.ok) {
		const message = body?.message || body?.error || `Bifrost virtual key creation failed (${response.status})`;
		throw new Error(message);
	}

	const virtualKey = body?.virtual_key || body;
	if (typeof virtualKey?.id !== "string" || typeof virtualKey?.value !== "string") {
		throw new Error("Bifrost virtual key response missing id or value");
	}

	return { id: virtualKey.id, value: virtualKey.value };
}

export interface DioEntitlement {
	email: string;
	virtualKeyId: string;
	virtualKeyValue: string;
	purchaseReference?: string;
	orderId?: string;
	checkoutId?: string;
	productId?: string;
	customerId?: string;
	createdAt: string;
}

const ENTITLEMENT_KEY_PREFIX = "entitlement:";
const PROCESSED_EVENTS_KEY = "processed_events";

export function entitlementStorageKey(email: string): string {
	return `${ENTITLEMENT_KEY_PREFIX}${normalizeEmail(email)}`;
}

export async function markEventProcessed(
	storage: { getItem: (key: string) => Promise<unknown>; setItem: (key: string, value: unknown) => Promise<void> },
	eventId: string,
): Promise<boolean> {
	const processed = ((await storage.getItem(PROCESSED_EVENTS_KEY)) as string[] | null) ?? [];
	if (processed.includes(eventId)) {
		return false;
	}
	processed.push(eventId);
	await storage.setItem(PROCESSED_EVENTS_KEY, processed);
	return true;
}

export async function loadDioEntitlement(
	storage: { getItem: (key: string) => Promise<unknown> },
	email: string,
): Promise<DioEntitlement | null> {
	const value = await storage.getItem(entitlementStorageKey(email));
	if (value && typeof value === "object") {
		const entitlement = value as DioEntitlement;
		if (
			typeof entitlement.email === "string" &&
			typeof entitlement.virtualKeyId === "string" &&
			typeof entitlement.virtualKeyValue === "string"
		) {
			return entitlement;
		}
	}
	return null;
}

export async function saveDioEntitlement(
	storage: { setItem: (key: string, value: unknown) => Promise<void> },
	entitlement: DioEntitlement,
): Promise<void> {
	await storage.setItem(entitlementStorageKey(entitlement.email), entitlement);
}

function isValidEmail(email: string): boolean {
	return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function cryptoUUID(): string {
	if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
		return crypto.randomUUID();
	}
	const bytes = new Uint8Array(16);
	if (typeof crypto !== "undefined" && typeof crypto.getRandomValues === "function") {
		crypto.getRandomValues(bytes);
	} else {
		for (let i = 0; i < bytes.length; i++) {
			bytes[i] = Math.floor(Math.random() * 256);
		}
	}
	bytes[6] = (bytes[6] & 0x0f) | 0x40;
	bytes[8] = (bytes[8] & 0x3f) | 0x80;
	const hex = Array.from(bytes, (b) => b.toString(16).padStart(2, "0")).join("");
	return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
}

