              </p>
              <input
                type="email"
                className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
                placeholder="Your email address"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") void handleCheckout();
                  if (e.key === "Escape") closeDioPrompt(false);
                }}
                autoFocus
              />
              {purchaseReference && (
                <p className="text-xs text-muted-foreground">
                  After completing checkout, click Claim to retrieve your key.
                </p>
              )}
              <div className="flex flex-wrap items-center justify-between gap-3">
                <button
                  type="button"
                  className="text-xs text-primary underline underline-offset-2"
                  onClick={() => setMode("recover")}
                >
                  Recover access by email
                </button>
                <div className="flex gap-2">
                  {purchaseReference && (
                    <button
                      type="button"
                      className="inline-flex h-9 items-center rounded-md bg-secondary px-3 text-sm font-medium hover:bg-secondary/80 disabled:opacity-50"
                      onClick={handleClaim}
                      disabled={loading}
                    >
                      <RefreshCw size={14} className="mr-1.5" />
                      {loading ? "Claiming..." : "Claim"}
                    </button>
                  )}
                  <button
                    type="button"
                    className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
                    onClick={handleCheckout}
                    disabled={loading}
                  >
                    <CreditCard size={14} className="mr-1.5" />
                    {loading ? "Loading..." : purchaseReference ? "Open checkout again" : "Buy credits"}
                  </button>
                </div>
              </div>
            </>
          )}
          {mode === "recover" && (
            <>
              <p className="text-sm text-muted-foreground">
                Enter the email you used to buy Dio credits. We'll restore your Bifrost key.
              </p>
              <input
                type="email"
                className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
                placeholder="Your email address"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") void handleRecover();
                  if (e.key === "Escape") closeDioPrompt(false);
                }}
                autoFocus
              />
              <div className="flex flex-wrap items-center justify-between gap-3">
                <button
                  type="button"
                  className="text-xs text-primary underline underline-offset-2"
                  onClick={() => setMode("purchase")}
                >
                  Buy credits
                </button>
                <button
                  type="button"
                  className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
                  onClick={handleRecover}
                  disabled={loading}
                >
                  <RefreshCw size={14} className="mr-1.5" />
                  {loading ? "Recovering..." : "Recover access"}
                </button>
              </div>
            </>
          )}
          {mode === "manual" && (
            <>
              <p className="text-sm text-muted-foreground">
                Paste a Bifrost virtual key manually. For development and support only.
              </p>
              <input
                type="password"
                className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm"
                placeholder="Dio virtual key"
                value={apiKey}
                onChange={(e) => setApiKey(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") void saveManualKey();
                  if (e.key === "Escape") closeDioPrompt(false);
                }}
                autoFocus
              />
              <div className="flex flex-wrap items-center justify-between gap-3">
                <button
                  type="button"
                  className="text-xs text-primary underline underline-offset-2"
                  onClick={() => setMode("purchase")}
                >
                  Back to purchase
                </button>
                <button
                  type="button"
                  className="inline-flex h-9 items-center rounded-md bg-primary px-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
                  onClick={saveManualKey}
                  disabled={loading}
                >
                  {loading ? "Saving..." : "Save key"}
                </button>
              </div>
            </>
