			output: 0,
			cacheRead: 0,
			cacheWrite: 0,
		});
	});

	it("normalizes emails to lowercase and trimmed", () => {
		expect(normalizeEmail("  ExamPle@Dio.Computer  ")).toBe("example@dio.computer");
