  if (!hasModel && config.pi.defaultModel) {
    merged.unshift(config.pi.defaultModel);
    merged.unshift("--model");
  }
  if (!hasThinking && config.pi.defaultThinking) {
    merged.unshift(config.pi.defaultThinking);
    merged.unshift("--thinking");
  }

  return merged;
}

