    const candidate: EvolutionCandidate = {
      policy: candidatePolicy,
      benchmark: candidateBenchmark,
      parentName: best.policy.name,
      iteration,
      novelty,
      accepted: false,
      parameterDelta,
      decision: {
        improves: false,
