    for (let i = matches.length - 1; i >= 0; i--) {
      try {
        return JSON.parse(matches[i]) as T;
      } catch {
        continue;
      }
    }
    throw new Error("No valid JSON block found in response.");
  } catch (error) {
    throw new Error(`Failed to parse agent JSON response: ${response}\nError: ${error}`);
  }
