  return (
    vector.realScore * 0.36 +
    vector.counterfactualRobustness * 0.22 +
    vector.mastery * 0.14 +
    vector.transfer * 0.12 +
    vector.lowConfusion * 0.1 +
    vector.evidenceReadiness * 0.06
