    if (leftValues[index] > rightValues[index]) wins += 1;
    if (leftValues[index] < rightValues[index]) losses += 1;
  }
  const aggregateDelta = aggregate(policyObjectiveVector(left)) - aggregate(policyObjectiveVector(right));
