  const normalized: SimulationWeights = {
    masteryGain: weights.masteryGain / sum,
    retention: weights.retention / sum,
    engagement: weights.engagement / sum,
    transfer: weights.transfer / sum,
    confusion: weights.confusion / sum
  };
