function buildProcessSvg(params: {
	title: string;
	subtitle: string;
	points: string[];
	labels: string[];
	style: string;
}): string {
	const palette = params.style === "dark"
		? { bg: "#101214", panel: "#181c20", ink: "#f6f1e7", muted: "#c9c1b3", accent: "#f59e0b", line: "#3f4650", arrow: "#9dd7c8", node: "#1f2937" }
		: { bg: "#f8f7f2", panel: "#ffffff", ink: "#171717", muted: "#525252", accent: "#0f766e", line: "#d8d3c7", arrow: "#0f766e", node: "#f0f4ef" };
	const points = params.points.length > 0 ? params.points : ["Define the inputs", "Process the inputs", "Verify the output"];
	const labels = params.labels.length > 0 ? params.labels : points.map((_, i) => `Step ${i + 1}`);
	const count = points.length;
	// Lay out the steps as a horizontal sequence with arrows in between. If we
	// have 5+ steps, wrap to a second row so the diagram stays readable.
	const perRow = count <= 4 ? count : Math.ceil(count / 2);
	const rows: number[] = [];
	let remaining = count;
	while (remaining > 0) {
		const take = Math.min(perRow, remaining);
		rows.push(take);
		remaining -= take;
	}
	const boxWidth = 232;
	const boxHeight = 152;
	const hGap = 64;
	const vGap = 90;
	const startX = (1200 - (Math.max(...rows) * boxWidth + (Math.max(...rows) - 1) * hGap)) / 2;
	const startY = 264;

	let cursor = 0;
	const renderBox = (point: string, label: string, x: number, y: number, index: number) => {
		const lines = wrapSvgText(point, 30);
		return `  <rect x="${x}" y="${y}" width="${boxWidth}" height="${boxHeight}" rx="14" fill="${palette.node}" stroke="${palette.accent}" stroke-width="2"/>
  <circle cx="${x + 22}" cy="${y + 22}" r="14" fill="${palette.accent}"/>
  <text x="${x + 22}" y="${y + 28}" text-anchor="middle" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-size="16" font-weight="800" fill="${params.style === "dark" ? "#111827" : "#ffffff"}">${index + 1}</text>
  <text x="${x + 44}" y="${y + 28}" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-size="16" font-weight="720" fill="${palette.ink}">${escapeHtml(label)}</text>
  ${svgTextLines(lines, x + 18, y + 60, { size: 18, fill: palette.ink, weight: 500 })}`;
	};
	const renderArrow = (x1: number, x2: number, y: number, key: string) => {
		const midY = y + boxHeight / 2;
		const xStart = x1 + boxWidth;
		const xEnd = x2;
		return `  <line x1="${xStart}" y1="${midY}" x2="${xEnd - 14}" y2="${midY}" stroke="${palette.arrow}" stroke-width="3" stroke-linecap="round" data-arrow-key="${key}"/>
  <polygon points="${xEnd - 14},${midY - 7} ${xEnd},${midY} ${xEnd - 14},${midY + 7}" fill="${palette.arrow}"/>`;
	};

	const boxes: string[] = [];
	const arrows: string[] = [];
	for (let r = 0; r < rows.length; r++) {
		const rowCount = rows[r];
		const rowWidth = rowCount * boxWidth + (rowCount - 1) * hGap;
		const rowStartX = (1200 - rowWidth) / 2;
		const y = startY + r * (boxHeight + vGap);
		const rowBoxes: { x: number; y: number; index: number }[] = [];
		for (let c = 0; c < rowCount; c++) {
			const x = rowStartX + c * (boxWidth + hGap);
			rowBoxes.push({ x, y, index: cursor });
			boxes.push(renderBox(points[cursor] ?? "", labels[cursor] ?? `Step ${cursor + 1}`, x, y, cursor));
			cursor += 1;
		}
		for (let c = 0; c < rowBoxes.length - 1; c++) {
			arrows.push(renderArrow(rowBoxes[c].x, rowBoxes[c + 1].x, rowBoxes[c].y, `h-${r}-${c}`));
		}
		// Vertical wrap-around arrow from last box in this row to first box in
		// the next row, on the right edge.
		if (r < rows.length - 1) {
			const last = rowBoxes[rowBoxes.length - 1];
			const nextRow = rows[r + 1];
			const nextRowWidth = nextRow * boxWidth + (nextRow - 1) * hGap;
			const nextRowStartX = (1200 - nextRowWidth) / 2;
			const firstX = nextRowStartX;
			const firstY = startY + (r + 1) * (boxHeight + vGap);
			const bendX = last.x + boxWidth + 32;
			const bendY1 = last.y + boxHeight / 2;
			const bendY2 = firstY + boxHeight / 2;
			arrows.push(
				`  <path d="M ${last.x + boxWidth} ${bendY1} L ${bendX} ${bendY1} L ${bendX} ${bendY2} L ${firstX - 14} ${bendY2}" fill="none" stroke="${palette.arrow}" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" data-arrow-key="v-${r}"/>` +
					`<polygon points="${firstX - 14},${bendY2 - 7} ${firstX},${bendY2} ${firstX - 14},${bendY2 + 7}" fill="${palette.arrow}"/>`,
			);
		}
	}

	return `<svg xmlns="http://www.w3.org/2000/svg" width="1200" height="760" viewBox="0 0 1200 760" role="img" aria-label="${escapeHtml(params.title)}">
  <rect width="1200" height="760" fill="${palette.bg}"/>
  <rect x="40" y="40" width="1120" height="680" rx="18" fill="${palette.panel}" stroke="${palette.line}" stroke-width="2"/>
  <text x="72" y="116" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-size="50" font-weight="760" fill="${palette.ink}">${escapeHtml(params.title)}</text>
  ${svgTextLines(wrapSvgText(params.subtitle, 82), 74, 166, { size: 23, fill: palette.muted, weight: 450 })}
  <line x1="72" y1="222" x2="1128" y2="222" stroke="${palette.line}" stroke-width="2"/>
  ${arrows.join("\n")}
  ${boxes.join("\n")}
  <text x="72" y="700" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-size="18" fill="${palette.muted}">Numbered boxes show the real order of operations; arrows are the causal or temporal links. Edit by passing new points and labels arrays.</text>
</svg>`;
}

function buildLocalImageSvg(params: {
	title: string;
	subtitle: string;
	points: string[];
	labels: string[];
	style: string;
	kind: string;
}): string {
	if (params.kind === "anatomy") return buildAnatomySvg(params);
	if (params.kind === "comparison") return buildComparisonSvg(params);
	if (params.kind === "process") return buildProcessSvg(params);
	return buildInfographicSvg(params);
}

async function generateOpenAiImage(params: {
	prompt: string;
	model: string;
	size: string;
	quality: string;
}): Promise<{ dataUrl: string; mimeType: string }> {
	const apiKey = await getProviderApiKey("openai");
	if (!apiKey) {
		throw new Error("No OpenAI API key configured. Add one in Settings -> Providers & Models -> OpenAI.");
	}

	const proxied = proxiedProviderRequestUrl("https://api.openai.com/v1/images/generations");
	const response = await fetch(proxied.url, {
		method: "POST",
		headers: {
			accept: "application/json",
			"content-type": "application/json",
			Authorization: `Bearer ${apiKey}`,
			"x-target-url": proxied.targetBaseUrl,
		},
		body: JSON.stringify({
			model: params.model,
			prompt: params.prompt,
			size: params.size,
			quality: params.quality,
			n: 1,
		}),
	});

	const payload = await response.json().catch(async () => ({ error: { message: await response.text().catch(() => response.statusText) } }));
	if (!response.ok) {
		const message = payload?.error?.message ?? response.statusText;
		throw new Error(`OpenAI image generation failed (${response.status}): ${String(message).slice(0, 500)}`);
	}

	const b64 = payload?.data?.[0]?.b64_json;
	if (!b64 || typeof b64 !== "string") {
		throw new Error("OpenAI image generation returned no base64 image data.");
	}

	return { dataUrl: `data:image/png;base64,${b64}`, mimeType: "image/png" };
}

function unavailableRemoteRuntimeMessage(runtime: KeatingAgentRuntimeConfig | undefined): string {
	if (!runtime || runtime.mode === "browser-only" || !runtime.executionEndpoint) {
		return [
			"# Remote Execution Unavailable",
			"",
			"Keating is running in browser-only mode. Run supported work in the browser and surface this fallback for operations that require native binaries, durable background compute, secure server-side secrets, public inbound networking, Docker/microVM isolation, or unrestricted host filesystem access.",
		].join("\n");
	}

	return "";
}

function stringifyRemoteResult(value: unknown): string {
	const text = typeof value === "string" ? value : JSON.stringify(value, null, 2);
	if (text.length <= 12000) return text;
	return `${text.slice(0, 12000)}\n\n[remote output truncated]`;
}

export interface KeatingToolsOptions {
	agentRuntime?: KeatingAgentRuntimeConfig;
	speech?: {
		settings: WebSpeechSettings;
		getApiKey: (provider: string) => Promise<string | undefined>;
	};
	setSystemPrompt?: (basePrompt: string) => void;
}

export async function createKeatingTools(
	storage: KeatingStorage,
	options: KeatingToolsOptions = {}
): Promise<AgentTool[]> {
	const tools: AgentTool[] = [
		// agent_runtime - Inspect current agent execution mode and fallback policy
		createTool(
			"agent_runtime",
			"Inspect current agent execution mode, available sandbox capabilities, and fallback policy. Use before attempting source execution, native tooling, secret-backed work, or remote-only operations.",
			{},
			async () => {
				const runtime = options.agentRuntime;
				if (!runtime) {
					return "Agent runtime config is unavailable. Assume browser-only local execution and surface clear fallback errors for remote-only work.";
				}

				const capabilities = Object.entries(runtime.capabilities)
					.map(([key, value]) => `- ${key}: ${String(value)}`)
					.join("\n");
				const remote = runtime.remote
					? [
						"",
						"## Remote Sandbox",
						`- provider: ${runtime.remote.provider}`,
						`- endpoint: ${runtime.remote.endpoint ?? "local server default"}`,
						`- region: ${runtime.remote.region ?? "default"}`,
						`- snapshot: ${runtime.remote.snapshot ?? "default"}`,
						`- cpu: ${runtime.remote.cpu ?? "default"}`,
						`- memory: ${runtime.remote.memory ?? "default"}`,
						`- disk: ${runtime.remote.disk ?? "default"}`,
					].join("\n")
					: "";

				const nodePodActive = isNodePodActive();
				const nodePod = nodePodActive
					? [
						"",
						"## NodePod Sandbox",
						`- active: true`,
						`- local endpoint: ${NODEPOD_LOCAL_ENDPOINT}`,
						`- operations: shell.exec, fs.read, fs.write, snapshot.create`,
					].join("\n")
					: "";

				return [
					`# Agent Runtime`,
					"",
					`- mode: ${runtime.mode}`,
					`- label: ${runtime.label}`,
					`- execution endpoint: ${runtime.executionEndpoint ?? "none"}`,
					`- cloud endpoint: ${runtime.cloudEndpoint ?? "none"}`,
					"",
					"## Capabilities",
					capabilities,
					remote,
					nodePod,
					"",
					"## Fallback Policy",
					`- local first: ${runtime.fallback.localFirst}`,
					`- remote available: ${runtime.fallback.remoteAvailable}`,
					`- message: ${runtime.fallback.message}`,
				].join("\n");
			}
		),

		// remote_execute - Send remote-only work to the configured microVM/cloud runtime
		createTool(
			"remote_execute",
			"Execute remote-only agent work through the configured microVM or Keating Cloud backend. Use only when browser-local tools cannot satisfy the request.",
			{
				operation: {
					type: "string",
					description: "Remote operation name, such as shell.exec, fs.read, fs.write, snapshot.create, or sandbox.provision",
				},
				payload: {
					type: "object",
					description: "Operation-specific JSON payload. For shell.exec, use { command, args, cwd, env, timeoutMs }.",
					additionalProperties: true,
				},
			},
			async (params) => {
				const runtime = options.agentRuntime;
				const operation = typeof params.operation === "string" ? params.operation.trim() : "";
				if (!operation) return "Operation required. Pass an operation parameter.";

				// Route through NodePod browser sandbox when active
				if (isNodePodActive()) {
					try {
						const result = await nodePodExecute(operation, params.payload);
						return [
							"# Remote Execution Result (NodePod)",
							"",
							`- mode: browser-nodepod`,
							`- operation: ${operation}`,
							"",
							stringifyRemoteResult(result),
						].join("\n");
					} catch (error) {
						return [
							"# Remote Execution Failed (NodePod)",
							"",
							`- operation: ${operation}`,
							`- error: ${error instanceof Error ? error.message : String(error)}`,
						].join("\n");
					}
				}

				if (!runtime || runtime.mode === "browser-only" || !runtime.executionEndpoint) {
					return unavailableRemoteRuntimeMessage(runtime);
				}

				const response = await fetch(`${runtime.executionEndpoint}/execute`, {
					method: "POST",
					headers: {
						accept: "application/json",
						"content-type": "application/json",
					},
					body: JSON.stringify({
						operation,
						payload: params.payload && typeof params.payload === "object" ? params.payload : {},
					}),
				});

				const contentType = response.headers.get("content-type") ?? "";
				const body = contentType.includes("application/json")
					? await response.json().catch(() => null)
					: await response.text();

				if (!response.ok) {
					return [
						"# Remote Execution Failed",
						"",
						`- status: ${response.status}`,
						`- mode: ${runtime.mode}`,
						`- endpoint: ${runtime.executionEndpoint}`,
						"",
						stringifyRemoteResult(body || response.statusText),
					].join("\n");
				}

				return [
					"# Remote Execution Result",
					"",
					`- mode: ${runtime.mode}`,
					`- operation: ${operation}`,
					"",
					stringifyRemoteResult(body),
				].join("\n");
			}
		),

		// animate - The model authors and renders a real manim-web or hyperframes animation
		createTool(
			"animate",
			"You write the animation itself. The tool renders whatever you author in a sandboxed iframe inline in the chat. Pass `kind` (manim|hyperframes|frames) and the corresponding `body`/authored content. For `manim`, write an `async function construct(scene, M) { ... }` that uses manim-web primitives (M.Text, M.FadeIn, M.Create, M.Axes, M.BarChart, M.Transform, M.Write, M.LaggedStart, M.Succession, etc.) to drive a real motion-based explanation. For `hyperframes`, write a full HTML document with GSAP timelines. For `frames`, write a structured frames/elements/connectors payload (legacy). The tool does not synthesize a template. Calling without authored `body`/frames is rejected with the exact shape required.",
			{
				topic: { type: "string", description: "The topic this animation explains" },
				kind: { type: "string", enum: ["manim", "hyperframes", "frames"], description: "Renderer: manim (raw JS scene using manim-web), hyperframes (HTML + GSAP), or frames (legacy structured payload)." },
				summary: { type: "string", description: "One-line summary shown above the animation. Recommended." },
				body: { type: "string", description: "REQUIRED for kind=manim|hyperframes. The JavaScript construct function or full HTML document you author — must explain THIS topic with real content, not a placeholder." },
				frames: { type: "array", description: "REQUIRED for kind=frames. Legacy structured payload." },
				follow_up: {
					type: "object",
					description: "Optional follow-up CTA shown on the last frame (frames kind only). Clicking dispatches a window event the chat can pick up.",
					properties: {
						kind: { type: "string", enum: ["question", "quiz"], description: "Follow-up type" },
						label: { type: "string", description: "Button label" },
						question: { type: "string" },
						choices: { type: "array", items: { type: "string" } },
						multi_select: { type: "boolean" },
						hint: { type: "string" },
					},
				},
			},
			async (params) => {
				const topic = (params.topic as string) || "";
				if (!topic) return "Topic required.";

				const kindRaw = typeof params.kind === "string" ? params.kind : "";
				if (kindRaw !== "manim" && kindRaw !== "hyperframes" && kindRaw !== "frames") {
					return [
						"Pick a `kind`: manim, hyperframes, or frames.",
						"  - `manim`: write an `async function construct(scene, M) { ... }` using manim-web primitives. The construct function runs against a real Scene and animates with real motion.",
						"  - `hyperframes`: write a full HTML document with GSAP timelines.",
						"  - `frames`: write a structured frames/elements/connectors payload (legacy).",
						"You MUST pass `body` (for manim/hyperframes) or `frames` (for frames) with real content for THIS topic. No template fallback exists.",
					].join("\n");
				}

				const kind = kindRaw;
				const body = typeof params.body === "string" ? params.body : "";
				const summary = typeof params.summary === "string" ? params.summary.trim() : "";

				if ((kind === "manim" || kind === "hyperframes") && body.trim().length < 50) {
					const manimExample =
						"async function construct(scene, M) {\n" +
						"  const title = new M.Text({ text: 'How DNS works', fontSize: 48, color: '#f4f1e8' });\n" +
						"  title.moveTo([0, 3, 0]);\n" +
						"  await scene.play(new M.Write(title));\n" +
						"  await scene.wait(0.5);\n" +
						"  const laptop = new M.Text({ text: 'Laptop', fontSize: 28 });\n" +
						"  laptop.moveTo([-4, 1, 0]);\n" +
						"  await scene.play(new M.FadeIn(laptop));\n" +
						"  const resolver = new M.Text({ text: 'Recursive resolver', fontSize: 28 });\n" +
						"  resolver.moveTo([4, 1, 0]);\n" +
						"  await scene.play(new M.FadeIn(resolver));\n" +
						"  await scene.play(new M.Create(new M.Arrow([-3, 0.5, 0], [3, 0.5, 0], { color: '#0f766e' })));\n" +
						"  await scene.wait(1.5);\n" +
						"}\n\n" +
						"Use any manim-web primitive via M.* and drive scene.play(...) / scene.wait(...) for real motion.";
					const hyperframesExample =
						"<!doctype html><html><body style=\"background:#0a0a0a;color:#f4f1e8;font-family:ui-monospace,monospace;margin:0;\">\n" +
						"  <section id=\"clip-0\" data-start=\"0\" data-duration=\"3\" style=\"opacity:0;\"><h2>Browser cache</h2><p>The OS asks the resolver</p></section>\n" +
						"  <section id=\"clip-3\" data-start=\"3\" data-duration=\"4\" style=\"opacity:0;\"><h2>Recursive resolver</h2><p>The heavy lifting happens here</p></section>\n" +
						"  <script src=\"https://cdn.jsdelivr.net/npm/gsap@3/dist/gsap.min.js\"></script>\n" +
						"  <script>\n" +
						"    const tl = gsap.timeline({paused:true});\n" +
						"    tl.to('#clip-0', {opacity:1, duration:0.4}, 0);\n" +
						"    tl.to('#clip-0', {opacity:0, duration:0.3}, 3);\n" +
						"    tl.to('#clip-3', {opacity:1, duration:0.4}, 3);\n" +
						"    tl.play(0);\n" +
						"  </script>\n</body></html>";
					return [
						`Author the ${kind} animation yourself. Pass \`body\` as real, non-placeholder ${kind === "manim" ? "JavaScript" : "HTML"} code for THIS topic (>=50 chars).`,
						"",
						"Example body shape:",
						"",
						kind === "manim" ? manimExample : hyperframesExample,
					].join("\n");
				}

				const resolved = resolveTopic(topic);

				let storyboard = "";
				let scene = "";
				let renderer: "manim" | "hyperframes" = "manim";
				let followUp: { kind: "question" | "quiz"; label: string; data: Record<string, unknown> } | undefined;
				if (kind === "manim" || kind === "hyperframes") {
					storyboard = `# Animation: ${resolved.title}\n\nRenderer: ${kind}\n\nThe model authored a raw ${kind} scene (see manifest for the source).`;
					scene = body;
					renderer = kind === "hyperframes" ? "hyperframes" : "manim";
				} else {
					const rawFrames = Array.isArray(params.frames) ? params.frames : [];
					const frames: Array<{
						title: string;
						narration?: string;
						elements: Array<Record<string, unknown>>;
						connectors?: Array<Record<string, unknown>>;
						highlight?: string[];
					}> = [];
					for (const raw of rawFrames) {
						if (!raw || typeof raw !== "object") continue;
						const frame = raw as Record<string, unknown>;
						const title = typeof frame.title === "string" ? frame.title.trim() : "";
						const elements = Array.isArray(frame.elements)
							? (frame.elements as Array<Record<string, unknown>>).filter(
									(e) =>
										e &&
										typeof e === "object" &&
										typeof (e as Record<string, unknown>).id === "string" &&
										typeof (e as Record<string, unknown>).x === "number" &&
										typeof (e as Record<string, unknown>).y === "number",
								)
							: [];
						if (!title || elements.length === 0) continue;
						frames.push({
							title,
							narration: typeof frame.narration === "string" ? frame.narration : undefined,
							elements,
							connectors: Array.isArray(frame.connectors) ? (frame.connectors as Array<Record<string, unknown>>) : undefined,
							highlight: Array.isArray(frame.highlight) ? (frame.highlight as string[]) : undefined,
						});
					}
					if (frames.length < 2 || elements_total(frames) < 3) {
						return [
							"Author the animation yourself. Pass `frames` as an array (>=2) of structured frames with at least 3 total elements. Example shape:",
							"",
							"frames: [",
							"  { title: \"Browser cache\", narration: \"OS asks the resolver...\", elements: [ { id: \"laptop\", kind: \"box\", x: 200, y: 300, label: \"Laptop\" }, { id: \"resolver\", kind: \"box\", x: 800, y: 300, label: \"Resolver\" } ], connectors: [ { from: \"laptop\", to: \"resolver\", kind: \"arrow\", label: \"query\" } ] },",
							"  { title: \"Root lookup\", elements: [ { id: \"root\", kind: \"circle\", x: 800, y: 200, label: \"\", glyph: \".\" } ], connectors: [ { from: \"resolver\", to: \"root\", kind: \"arrow\" } ] }",
							"]",
							"",
							"Use real concept names, real labels, real causal order. viewBox is 1000x600. No template fallback exists.",
						].join("\n");
					}
					const followUpRaw = params.follow_up && typeof params.follow_up === "object" ? (params.follow_up as Record<string, unknown>) : null;
					followUp = followUpRaw && (followUpRaw.kind === "question" || followUpRaw.kind === "quiz")
						? {
								kind: followUpRaw.kind as "question" | "quiz",
								label: typeof followUpRaw.label === "string" ? followUpRaw.label : (followUpRaw.kind === "question" ? "Check your understanding" : "Take the quiz"),
								data: followUpRaw,
							}
						: undefined;
					storyboard = buildAnimationStoryboardFromFrames(resolved.title, frames);
					renderer = loadKeatingUiSettings().animationRenderer;
					scene = renderer === "hyperframes" ? buildHyperframesComposition(resolved, storyboard) : buildManimScene(resolved, storyboard);
				}
				const animationPayload: Record<string, unknown> = {
					topic: resolved.title,
					kind,
					summary: summary || undefined,
				};
				if (kind === "manim" || kind === "hyperframes") {
					animationPayload.body = body;
				} else if (kind === "frames") {
					animationPayload.frames = Array.isArray(params.frames) ? params.frames : [];
					animationPayload.followUp = followUp;
				}

				const manifest = JSON.stringify(
					{
						topic: resolved.title,
						slug: resolved.slug,
						domain: resolved.domain,
						kind,
						sourceBytes: body.length,
						generatedAt: new Date().toISOString(),
					},
					null,
					2,
				);
				const saved = await storage.saveAnimation(topic, storyboard, scene, manifest, renderer);

				return [
					`[artifact://animation/${saved.id}]`,
					"",
					`<keating-animation json=${JSON.stringify(JSON.stringify(animationPayload))} />`,
				].join("\n");
			}
		),

		// plan - Generate lesson plan
		createTool(
			"plan",
			"Save a lesson plan you author yourself, grounded in the real material — for EVERY topic, including familiar ones. There is no template: you must pass `content`. Format it as markdown: a `- Summary: ...` line, then `## Phase Title` sections each with a one-line purpose followed by `- ` action bullets. The plan is its own artifact; do NOT also build a quiz here — quizzes are crafted separately, after the learner has gone through the lesson.",
			{
				topic: { type: "string", description: "The topic this lesson plan covers" },
				content: { type: "string", description: "REQUIRED. Agent-authored lesson plan markdown grounded in the real material. Use `- Summary:` plus `## Phase` sections with purpose lines and `- ` bullets." },
			},
			async (params) => {
				const topic = (params.topic as string) || "";
				if (!topic) {
					return "Topic required. Pass a topic parameter.";
				}

				const authoredContent = typeof params.content === "string" ? params.content.trim() : "";
				if (authoredContent.length < 80) {
					return "Author the lesson plan yourself. Pass `content` as markdown grounded in the real material: a `- Summary:` line, then `## Phase` sections each with a one-line purpose and `- ` action bullets. No template fallback exists.";
				}

				const saved = await storage.saveLessonPlan(topic, authoredContent, {
					domain: resolveTopic(topic).domain,
					authored: true,
				});
				return `[artifact://plan/${saved.id}]\n\n${authoredContent}`;
			}
		),

		// map - Generate concept map
		createTool(
			"map",
			"Save a Mermaid concept map you author yourself, with real concepts and the actual relationships between them — for EVERY topic, including familiar ones. There is no template: you must pass `mermaid`.",
			{
				topic: { type: "string", description: "The topic this concept map covers" },
				mermaid: { type: "string", description: "REQUIRED. Agent-authored Mermaid diagram (e.g. `graph TD; A[Concept]-->B[...]`) with real nodes and edges grounded in the material." },
			},
			async (params) => {
				const topic = (params.topic as string) || "";
				if (!topic) return "Topic required.";

				const authoredMermaid = typeof params.mermaid === "string" ? params.mermaid.trim() : "";
				if (authoredMermaid.length < 20) {
					return "Author the concept map yourself. Pass a `mermaid` diagram (e.g. `graph TD; A[Concept]-->B[Related]`) with real nodes and relationships grounded in the material. No template fallback exists.";
				}
				const saved = await storage.saveLessonMap(topic, authoredMermaid);

				return `[artifact://map/${saved.id}]\n\n\`\`\`mermaid\n${authoredMermaid}\n\`\`\``;
			}
		),

		createTool(
			"generate_image",
			"Create a learning image. Supports real OpenAI image models for raster images and browser-local SVG diagrams for labeled anatomy/comparison/process visuals. You MUST author the content yourself by passing `title`, `subtitle`, and at least 3 `points` describing what the visual should communicate — generic titles like 'Learning visual' or empty point lists are rejected. Pick the `kind` based on what the visual needs to show: 'anatomy' for labeled structures (e.g. antibody Y-shape), 'comparison' for size/category bars, 'process' for numbered step-by-step flows with arrows (e.g. DNS resolution stages, Krebs cycle, signal transduction), and 'cards' for grouped concepts. Use `mode='model'` when the learner asks for an actual generated picture; 'auto' tries the image model when an OpenAI key is configured and falls back to SVG.",
			{
				title: { type: "string", description: "REQUIRED. Short, specific title for the visual that reflects THIS topic (e.g. 'DNS resolution steps' or 'IgG antibody anatomy'), not 'Learning visual'." },
				subtitle: { type: "string", description: "REQUIRED. One-sentence framing caption that names the specific idea being illustrated." },
				prompt: { type: "string", description: "Detailed image-model prompt. Required for mode=model; should describe labels, diagram layout, style, and educational goal." },
				mode: { type: "string", description: "auto, model, or svg. auto tries the image model when an OpenAI key is configured, then falls back to SVG." },
				kind: { type: "string", description: "cards, anatomy, comparison, or process. Used for local SVG fallback and diagram layout. Use 'process' for ordered step-by-step flows with arrows; 'anatomy' for labeled structures; 'comparison' for size/category bars; 'cards' for grouped concepts." },
				imageModel: { type: "string", description: "OpenAI image model, such as gpt-image-1.5, gpt-image-1, or gpt-image-1-mini." },
				size: { type: "string", description: "Image size for model mode: 1024x1024, 1536x1024, or 1024x1536." },
				quality: { type: "string", description: "Image quality for model mode: low, medium, or high." },
				points: {
					type: "array",
					description: "REQUIRED (>=3). Concrete teaching points to visualize. For 'process' these become the numbered steps; for 'anatomy' they become label callouts; for 'comparison' they become bar values; for 'cards' they become card body text. Generic points like 'Core idea' are rejected.",
					items: { type: "string" },
				},
				labels: {
					type: "array",
					description: "Optional labels for the visual blocks. For 'process' these become the step titles shown in each box; for 'anatomy' they become structure names.",
					items: { type: "string" },
				},
				style: {
					type: "string",
					description: "Visual style: light or dark",
				},
			},
			async (params) => {
				const title = String(params.title ?? "").trim();
				const subtitle = String(params.subtitle ?? "").trim();
				const points = asStringArray(params.points, []);
				const labels = asStringArray(params.labels, []);
				const style = String(params.style ?? "light").toLowerCase() === "dark" ? "dark" : "light";
				const requestedMode = String(params.mode ?? "auto").toLowerCase();
				const mode = requestedMode === "model" || requestedMode === "svg" ? requestedMode : "auto";
				const kindRaw = String(params.kind ?? "cards").toLowerCase();
				const kind = ["anatomy", "comparison", "process", "cards"].includes(kindRaw) ? kindRaw : "cards";

				// Reject generic/templated content the same way plan/map/verify/quiz
				// do — the visual must be grounded in real material.
				const genericTitle = !title || title.toLowerCase() === "learning visual";
				const genericSubtitle = !subtitle || subtitle.toLowerCase() === "a compact visual summary for this concept.";
				const genericPoints = points.length < 3 || points.every((p) => /^(core idea|key relationship|learner takeaway)$/i.test(p.trim()));
				if (genericTitle || genericSubtitle || genericPoints) {
					return [
						"Author the image content yourself. The tool will not synthesize a generic visual. Pass:",
						"- `title`: a topic-specific title (e.g. 'How DNS resolves a name', 'IgG Y-shape anatomy') — not 'Learning visual'.",
						"- `subtitle`: a one-sentence framing that names the actual idea.",
						`- \`points\`: >=3 concrete points that will become the visual's content${
							kind === "process"
								? " (for process kind, these are the numbered steps in order)"
								: kind === "anatomy"
									? " (for anatomy kind, these are the labeled-structure callouts)"
									: kind === "comparison"
										? " (for comparison kind, include the value/size in each point, e.g. '150 kDa full Y')"
										: " (real concepts grounded in the material)"
						}.`,
						"- `labels` (optional): per-block labels for the visual.",
						"No template fallback exists.",
					].join("\n");
				}

				const finalTitle = title;
				const finalSubtitle = subtitle;
				const imageModel = String(params.imageModel ?? "gpt-image-1.5").trim() || "gpt-image-1.5";
				const sizeRaw = String(params.size ?? "1024x1024");
				const size = ["1024x1024", "1536x1024", "1024x1536"].includes(sizeRaw) ? sizeRaw : "1024x1024";
				const qualityRaw = String(params.quality ?? "medium").toLowerCase();
				const quality = ["low", "medium", "high"].includes(qualityRaw) ? qualityRaw : "medium";
				const prompt = String(params.prompt ?? "").trim() || [
					`Create a clear educational ${kind === "cards" ? "infographic" : `${kind} diagram`} titled "${finalTitle}".`,
					finalSubtitle,
					points.length > 0 ? `Include these ideas: ${points.join("; ")}.` : "",
					labels.length > 0 ? `Use labels: ${labels.join(", ")}.` : "",
					"Make it legible, accurate, and suitable for a learner studying from the image.",
				].filter(Boolean).join(" ");

				let payload: Record<string, string>;
				let note = "";
				if (mode !== "svg") {
					try {
						const generated = await generateOpenAiImage({ prompt, model: imageModel, size, quality });
						payload = {
							title: finalTitle,
							alt: finalSubtitle,
							dataUrl: generated.dataUrl,
							mimeType: generated.mimeType,
							model: imageModel,
							prompt,
						};
					} catch (error) {
						if (mode === "model") throw error;
						note = `\n\n_Image model unavailable, rendered a local SVG fallback instead: ${error instanceof Error ? error.message : String(error)}_`;
						payload = {
							title: finalTitle,
							alt: finalSubtitle,
							svg: buildLocalImageSvg({ title: finalTitle, subtitle: finalSubtitle, points, labels, style, kind }),
							model: "svg-local",
							prompt,
						};
					}
				} else {
					payload = {
						title: finalTitle,
						alt: finalSubtitle,
						svg: buildLocalImageSvg({ title: finalTitle, subtitle: finalSubtitle, points, labels, style, kind }),
						model: "svg-local",
						prompt,
					};
				}

				return [
					`# Generated Image: ${finalTitle}`,
					"",
					finalSubtitle,
					note,
					"",
					`<keating-image json=${JSON.stringify(JSON.stringify(payload))} />`,
				].join("\n");
			}
