				let note = "";
				if (mode !== "svg") {
					try {
						const generated = await generateOpenAiImage({ prompt, model: imageModel, size, quality });
						payload = {
							title: finalTitle,
							alt: finalSubtitle,
							dataUrl: generated.dataUrl,
							mimeType: generated.mimeType,
							model: imageModel,
							prompt,
						};
