						svg: buildLocalImageSvg({ title: finalTitle, subtitle: finalSubtitle, points, labels, style, kind }),
						model: "svg-local",
						prompt,
					};
				}

				return [
					`# Generated Image: ${finalTitle}`,
					"",
					finalSubtitle,
					note,
					"",
					`<keating-image json=${JSON.stringify(JSON.stringify(payload))} />`,
