	const pod = await getNodePod();
	if (!pod) throw new Error("NodePod unavailable");
	const path = parent.endsWith("/") ? `${parent}${name}` : `${parent}/${name}`;
	if (isDir) {
		await pod.fs.mkdir(path, { recursive: true });
	} else {
		await writeFileToVfs(pod, path, "");
