export interface WebSpeechSettings {
	enabled: boolean;
	/** Active provider. Defaults to "gemini-live" for back-compat. */
	providerId: SpeechProviderId;
	/** Active model for the chosen provider. */
	model: string;
	/** Active voice for the chosen provider. */
	voiceName: string;
